import{_ as a,c as r,o as e,ag as d}from"./chunks/framework.XjE0kKti.js";const o="/gatewayweb/docs/assets/hub0007-overview.CYPPXMK4.png",c=JSON.parse('{"title":"系统节点监控","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0007.md","filePath":"modules/hub0007.md","lastUpdated":1776841524000}'),h={name:"modules/hub0007.md"};function l(n,t,i,s,p,b){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="系统节点监控" tabindex="-1">系统节点监控 <a class="header-anchor" href="#系统节点监控" aria-label="Permalink to &quot;系统节点监控&quot;">​</a></h1><p>在网关控制台中查看<strong>已纳入监控的系统节点</strong>运行状态：先在上方列表中定位并选择节点，再在下方监控面板查看 CPU、内存、磁盘、磁盘 IO、网络与进程等多维指标的时序趋势，用于巡检、容量评估与异常定位。</p><p><img src="'+o+'" alt="系统节点监控：节点列表与监控面板"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>系统节点监控</strong>面向运维与管理员，主要解决：</p><ul><li><strong>节点是否在线且可用</strong>：通过“最后更新”等字段判断采集是否持续。</li><li><strong>资源是否逼近上限</strong>：CPU/内存/磁盘使用率是否长期处于高位或频繁触发预警区间。</li><li><strong>异常定位</strong>：结合磁盘 IO、网络与进程概览，缩小问题范围（计算/存储/网络/进程）。</li></ul><p>本页为“节点维度”的监控视图：在同一页面内完成节点选择与多指标联动查看。</p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>系统设置</strong> → <strong>系统节点监控</strong>。</p><hr><h2 id="使用流程" tabindex="-1">使用流程 <a class="header-anchor" href="#使用流程" aria-label="Permalink to &quot;使用流程&quot;">​</a></h2><h3 id="_1-在节点列表中定位目标" tabindex="-1">1. 在节点列表中定位目标 <a class="header-anchor" href="#_1-在节点列表中定位目标" aria-label="Permalink to &quot;1. 在节点列表中定位目标&quot;">​</a></h3><p>通过筛选条件缩小范围（支持 <strong>更多条件</strong> 展开），然后点击 <strong>查询</strong>。</p><p>常用筛选项：</p><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>主机名</td><td>按主机名检索。</td></tr><tr><td>IP地址</td><td>按 IP 地址检索。</td></tr><tr><td>操作系统</td><td>Linux / Windows / MacOS / Unix / 其他。</td></tr><tr><td>服务器类型</td><td>物理服务器 / 虚拟服务器 / 未知。</td></tr><tr><td>服务器位置（更多条件）</td><td>机房、区域或部署位置等自定义字段。</td></tr></tbody></table><h3 id="_2-选择节点加载监控" tabindex="-1">2. 选择节点加载监控 <a class="header-anchor" href="#_2-选择节点加载监控" aria-label="Permalink to &quot;2. 选择节点加载监控&quot;">​</a></h3><p>在表格中<strong>单击某一行</strong>，系统将该行的 <strong>节点 ID</strong> 作为监控目标，并在下方加载对应指标数据。未选择节点时，下方会提示“请在上方列表中选择一个节点查看监控数据”。</p><h3 id="_3-调整时间范围与刷新" tabindex="-1">3. 调整时间范围与刷新 <a class="header-anchor" href="#_3-调整时间范围与刷新" aria-label="Permalink to &quot;3. 调整时间范围与刷新&quot;">​</a></h3><p>每个图表都提供：</p><ul><li><strong>时间范围选择</strong>：支持快捷项（如最近 1/6/12/24 小时等）或自定义区间。</li><li><strong>刷新</strong>：只刷新当前图表对应的数据。</li></ul><p>当你在任一图表中更改时间范围后，系统会更新当前监控的时间窗口，并按新时间范围重新查询该图表数据。</p><hr><h2 id="节点列表字段说明" tabindex="-1">节点列表字段说明 <a class="header-anchor" href="#节点列表字段说明" aria-label="Permalink to &quot;节点列表字段说明&quot;">​</a></h2><p>上方列表用于确认“当前查看的是哪台机器”，常见字段包括：</p><table tabindex="0"><thead><tr><th>列</th><th>用途</th></tr></thead><tbody><tr><td>节点ID</td><td>节点唯一标识；选择节点与查询监控指标时使用。</td></tr><tr><td>主机名 / IP地址</td><td>资产定位与连通性排查的基础信息。</td></tr><tr><td>操作系统 / 系统版本 / 架构</td><td>用于区分平台差异（例如 Windows/Linux 指标口径、软件包兼容等）。</td></tr><tr><td>服务器类型 / 服务器位置</td><td>便于与容量规划策略、机房区域对应。</td></tr><tr><td>最后更新</td><td>判断监控采集是否持续；若长期不更新，可能是采集端离线或链路异常。</td></tr><tr><td>创建/修改信息</td><td>审计字段，用于追溯录入与变更。</td></tr></tbody></table><hr><h2 id="监控面板说明" tabindex="-1">监控面板说明 <a class="header-anchor" href="#监控面板说明" aria-label="Permalink to &quot;监控面板说明&quot;">​</a></h2><p>选择节点后，下方监控面板包含：</p><ol><li><strong>服务器信息卡片</strong>：展示主机名、操作系统、系统版本、架构、服务器类型与 IP 地址，便于快速确认目标节点。</li><li><strong>多指标图表</strong>：按行展示 CPU/内存、磁盘/磁盘 IO、网络/进程等视图。</li></ol><h3 id="cpu-使用率" tabindex="-1">CPU 使用率 <a class="header-anchor" href="#cpu-使用率" aria-label="Permalink to &quot;CPU 使用率&quot;">​</a></h3><p>用于观察总 CPU 使用率及其随时间变化的趋势。若长期高位（例如持续接近 80% 以上）或存在尖峰，建议结合进程与业务窗口进一步定位。</p><h3 id="内存使用率" tabindex="-1">内存使用率 <a class="header-anchor" href="#内存使用率" aria-label="Permalink to &quot;内存使用率&quot;">​</a></h3><p>展示内存使用率趋势，并在明细提示中包含交换分区（swap）等信息（若采集侧上报）。当内存长期高位或 swap 频繁增长时，通常需要排查内存泄漏、缓存策略或容量不足。</p><h3 id="磁盘使用率" tabindex="-1">磁盘使用率 <a class="header-anchor" href="#磁盘使用率" aria-label="Permalink to &quot;磁盘使用率&quot;">​</a></h3><p>用于观察磁盘空间占用趋势。磁盘接近满容量会导致写入失败、服务异常与连锁故障；建议在接近预警区间时就介入清理或扩容。</p><h3 id="磁盘-io" tabindex="-1">磁盘 IO <a class="header-anchor" href="#磁盘-io" aria-label="Permalink to &quot;磁盘 IO&quot;">​</a></h3><p>用于定位存储瓶颈：读写吞吐/延迟/IOPS（具体指标随采集数据而定）。若 IO 长期冲高但 CPU/内存正常，常见原因包括慢查询、批处理、日志爆量或大文件读写。</p><h3 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h3><p>展示上行/下行（或收发）流量趋势，便于识别突发流量、备份窗口或异常外联。网络与 CPU/IO 同时异常时，可优先检查上游依赖与网络策略。</p><h3 id="进程" tabindex="-1">进程 <a class="header-anchor" href="#进程" aria-label="Permalink to &quot;进程&quot;">​</a></h3><p>从主机层面汇总进程相关监控（如平均 CPU/内存占用等），帮助判断是否存在异常占用或与网关进程相关的波动。</p><hr><h2 id="空状态与排查" tabindex="-1">空状态与排查 <a class="header-anchor" href="#空状态与排查" aria-label="Permalink to &quot;空状态与排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>含义与建议</th></tr></thead><tbody><tr><td>下方提示请选择节点</td><td>还未在上方表格中点击选择节点。</td></tr><tr><td>图表显示“暂无数据”</td><td>在所选时间范围内没有采集数据；可扩大时间范围，或检查采集是否正常、节点是否在线。</td></tr><tr><td>最后更新长期不变</td><td>可能采集端离线、指标上报中断或网关与监控服务链路异常。</td></tr></tbody></table><p>如需快速定位链路问题，建议按顺序检查：节点是否可达 → 采集代理是否在线 → 指标上报周期 → 网关服务与监控数据源连通性。</p>',47)])])}const P=a(h,[["render",l]]);export{c as __pageData,P as default};
